"use strict";(globalThis.webpackChunkmid_soul_wiki=globalThis.webpackChunkmid_soul_wiki||[]).push([[9562],{3212(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/03/05/v2-0-x","metadata":{"permalink":"/MidSoul-Wiki/blog/2026/03/05/v2-0-x","source":"@site/blog/2026-03-05-v2-0-x.md","title":"v2.0.x \u56de\u54cd\u7eaa\u5143","description":"\u5348\u591c\u7075\u9b42\u66f4\u65b0\u65e5\u5fd7 \xbb 2.0 \u25c8 \u56de\u54cd\u7eaa\u5143","date":"2026-03-05T08:56:43.000Z","tags":[{"inline":false,"label":"\u65b0\u529f\u80fd","permalink":"/MidSoul-Wiki/blog/tags/feature","description":"\u65b0\u589e\u529f\u80fd\u6216\u73a9\u6cd5"},{"inline":false,"label":"\u5e73\u8861\u8c03\u6574","permalink":"/MidSoul-Wiki/blog/tags/balance","description":"\u6e38\u620f\u6570\u503c\u4e0e\u673a\u5236\u7684\u5e73\u8861\u6027\u8c03\u6574"},{"inline":false,"label":"\u5730\u56fe\u66f4\u65b0","permalink":"/MidSoul-Wiki/blog/tags/map","description":"\u5730\u56fe\u5185\u5bb9\u7684\u65b0\u589e\u6216\u6539\u52a8"},{"inline":false,"label":"\u80fd\u529b\u8c03\u6574","permalink":"/MidSoul-Wiki/blog/tags/ability","description":"\u5929\u8d4b\u3001\u6280\u80fd\u6216\u5b9d\u7269\u7684\u6539\u52a8"}],"hasTruncateMarker":true,"authors":[{"name":"\u5fc3\u706b\u8ba1\u5212","title":"\u5236\u4f5c\u7ec4","url":"https://github.com/heart-fire-project","key":"hfp","page":null}],"frontMatter":{"title":"v2.0.x \u56de\u54cd\u7eaa\u5143","date":"2026-03-05T08:56:43.000Z","authors":["hfp"],"tags":["feature","balance","map","ability"]},"unlisted":false,"nextItem":{"title":"v1.0.x \u7075\u9b42\u4e0e\u5b88\u536b","permalink":"/MidSoul-Wiki/blog/2026/03/05/v1-0-x"}},"content":"## \u5348\u591c\u7075\u9b42\u66f4\u65b0\u65e5\u5fd7 \xbb 2.0 \u25c8 \u56de\u54cd\u7eaa\u5143\\n\\n### \u8bf4\u660e\\n- \u672c\u6b21\u66f4\u65b0\u4e3a\u8de8\u7248\u672c\u66f4\u65b0\uff0c\u6e38\u73a9\u66f4\u65b0\u9700\u4f7f\u7528 **1.21.11** \u7248\u672c\u5348\u591c\u7075\u9b42**\u65b0\u5730\u56fe**\u8fdb\u884c\u6e38\u620f\\n\\n\x3c!-- truncate --\x3e\\n\\n### \u5185\u5bb9\\n- \u65b0\u589e\u5bf9\u5c40\u5185\u6559\u7a0b\\n- \u65b0\u589e\u77ed\u671f\u5206\u7cfb\u7edf\\n- \u65b0\u589e\u56de\u54cd\u7cfb\u7edf\\n- \u65b0\u589e\u88c5\u9970\u54c1\u7cfb\u7edf\\n- \u65b0\u589e\u5185\u7f6e\u80cc\u666f\u97f3\u4e50\\n- \u65b0\u589e\u80fd\u529b\u81ea\u9009\u529f\u80fd\\n- \u65b0\u589e\u73a9\u5bb6\u4e2a\u4eba\u8bbe\u5b9a\u529f\u80fd\\n- \u65b0\u589e\u81ea\u5b9a\u4e49\u5730\u56fe\u529f\u80fd\uff08\u9700\u901a\u8fc7\u8c03\u8bd5\u9762\u677f\u5f00\u542f\uff09\\n- \u65b0\u589e\u9635\u8425\u81ea\u9009\u529f\u80fd\uff08\u9700\u901a\u8fc7\u8c03\u8bd5\u9762\u677f\u5f00\u542f\uff09\\n- \u65b0\u589e\u5730\u56fe \u201c\u5fc3\u706b\u7279\u533a\u201d\\n- \u91cd\u5236\u8fdb\u5ea6\u7cfb\u7edf\\n- \u4e3b\u5927\u5385\u8fed\u4ee3\u5347\u7ea7\uff0c\u65b0\u589e\u90e8\u5206\u529f\u80fd\\n- \u8c03\u8bd5\u9762\u677f\u8fed\u4ee3\u5347\u7ea7\uff0c\u65b0\u589e\u90e8\u5206\u529f\u80fd\\n\\n### \u663e\u793a\\n- \u65b0\u589e\u90e8\u5206\u5929\u8d4b\u7684\u51b7\u5374\u65f6\u95f4\u663e\u793a\\n- \u65b0\u589e\u6240\u6709\u80fd\u529b\u7684\u6807\u7b7e\u663e\u793a\\n- \u8c03\u6574\u6570\u4e2a\u80fd\u529b\u7684\u7269\u54c1\u6837\u5f0f\\n- \u7f29\u5c0f\u4e86\u7075\u9b42\u4e4b\u706f\u7684\u5927\u5c0f\\n- \u4f18\u5316\u591a\u5904\u52a8\u753b\u4e0e\u663e\u793a\u6548\u679c\\n- \u4fee\u590d\u91cd\u8fdb\u6e38\u620f\u540e\u90e8\u5206\u80fd\u529b\u7684\u7279\u6548\u4e0d\u6d88\u5931\u7684\u95ee\u9898\\n- \u4fee\u590d\u7279\u5b9a\u60c5\u51b5\u4e0b\uff0c\u5782\u6b7b\u5012\u8ba1\u65f6\u663e\u793a\u6709\u8bef\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u9b42\u5b9d\u7269 \u201c\u5171\u9e23\u5f15\u529b\u201d \u751f\u6548\u65f6\u788e\u7247\u4f4d\u7f6e\u6709\u8bef\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u9b42\u5b9d\u7269 \u201c\u76f8\u4f4d\u66ff\u6362\u201d \u5728\u8ddd\u79bb\u8f83\u8fdc\u65f6\u7c92\u5b50\u7279\u6548\u5f02\u5e38\u7684\u95ee\u9898\\n- \u4fee\u590d\u7269\u54c1\u680f\u53ef\u80fd\u77ed\u65f6\u95f4\u51fa\u73b0\u672a\u4fee\u9970\u7269\u54c1\u7684\u95ee\u9898\\n- \u4fee\u590d\u5728\u88c5\u8f7d\u8bed\u8a00\u5305\u7684\u72b6\u51b5\u4e0b\uff0c\u90e8\u5206\u6587\u672c\u4f1a\u51fa\u73b0\u53c2\u6570\u672a\u66ff\u6362\u7684\u95ee\u9898\\n\\n### \u8fdb\u7a0b\\n- \u65b0\u589e\u7075\u9b42\u5b88\u536b\u8005\u4fdd\u5e95\u673a\u5236\\n- \u8c03\u6574\u7075\u6c14\u7b49\u7ea7\u6240\u9700\u788e\u7247\u767e\u5206\u6bd4\uff1a30/50/70 \u2192 50/70/90\\n- \u8c03\u6574\u7075\u6c14\u6ee1\u6ea2\u673a\u5236\uff1a\\n  - \u65f6\u95f4\u89e6\u53d1\u9608\u503c\u4e0b\u964d\uff1a20m \u2192 10m\\n  - \u6536\u96c6\u9636\u6bb5\u4e0b\u5728\u6ee1\u6ea2\u65f6\u6536\u96c6\u788e\u7247\u5c06\u52a0\u901f 5s\\n  - \u4e0d\u518d\u4f7f\u6c14\u606f\u63a2\u6d4b\u673a\u5236\u5931\u6548\\n- \u4f18\u5316\u521d\u59cb\u9636\u6bb5\u4e0b\u7684\u65c1\u89c2\u8005\u4f53\u9a8c\\n- \u4f18\u5316\u788e\u7247\u6536\u96c6\u7684\u5730\u56fe\u5185\u53d8\u91cf\u5c55\u73b0\\n- \u4fee\u590d\u6700\u7ec8\u7ed3\u7b97\u65f6\uff0c\u7075\u9b42\u65b9\u73a9\u5bb6\u53ef\u4ee5\u901a\u8fc7\u9000\u51fa\u6e38\u620f\u6539\u53d8\u5224\u5b9a\u7684\u95ee\u9898\\n\\n### \u6e38\u620f\\n- \u65b0\u589e\u7075\u9b42\u53d7\u51fb\u540e\u77ed\u65f6\u95f4\u65e0\u654c\u673a\u5236\\n- \u65b0\u589e\u7075\u9b42\u5b88\u536b\u8005\u6389\u7ebf\u91cd\u8fde\u673a\u5236\\n- \u7531\u4e8e\u6548\u679c\u91cd\u5236\uff0c\u66f4\u540d\u4e86\u6570\u4e2a\u6280\u80fd\\n- \u8c03\u6574\u591a\u6570\u80fd\u529b\u63cf\u8ff0\uff0c\u5982\u672a\u5728\u4e0b\u6587\u63d0\u53ca\u5219\u6548\u679c\u4e0d\u53d8\\n- \u8c03\u6574\u7075\u9b42\u73a9\u5bb6\u5165\u573a\u673a\u5236\\n- \u8c03\u6574\u7075\u9b42\u4e4b\u706f\u4e0e\u4f20\u9001\u95e8\u7684\u751f\u6210\u673a\u5236\\n- \u8c03\u6574\u73a9\u5bb6\u8ffd\u8e2a\u6807\u8bb0\u5b58\u5728\u65f6\u957f\uff1a3s \u2192 4s\\n- \u8c03\u6574\u7075\u9b42\u5b9d\u7269\u76d2\u673a\u5236\uff1a\\n  - \u73b0\u5728\u4f1a\u6709\u7c92\u5b50\u63d0\u793a\u5176\u4f4d\u7f6e\\n  - \u6301\u6709\u5b9d\u7269\u65f6\u6253\u5f00\u4f1a\u989d\u5916\u6062\u590d\u8840\u91cf\\n- \u8c03\u6574\u4f20\u9001\u95e8\u673a\u5236\uff1a\\n  - \u4ec5\u8fdb\u884c\u4e00\u6b21\u751f\u6210\uff0c\u4e14\u76f4\u63a5\u751f\u6210 2 \u4e2a\u4f20\u9001\u95e8\\n  - \u4f20\u9001\u95e8\u73b0\u5728\u9700\u8981\u8fdb\u884c\u4ea4\u4e92\u6765\u5f00\u542f\uff0c\u5f00\u542f\u540e\u624d\u4f1a\u4f7f\u7075\u9b42\u590d\u6d3b\\n  - \u5145\u80fd\u9636\u6bb5\u4e2d\u6536\u96c6\u788e\u7247\u53ef\u4ee5\u5ef6\u957f\u5012\u8ba1\u65f6 10s\\n  - \u5f00\u95e8\u9636\u6bb5\u4e2d\u73a9\u5bb6\u7684\u6280\u80fd\u51b7\u5374\u901f\u7387 +100%\\n  - \u4ea4\u4e92\u9700\u8981\u7d2f\u8ba1 50s\uff0c\u5141\u8bb8\u591a\u4eba\u540c\u65f6\u4ea4\u4e92\uff1b\u672a\u4ea4\u4e92\u65f6\u8fdb\u5ea6\u56de\u9000\\n  - \u5269\u4f59\u65f6\u95f4\u4e0d\u8db3 30 \u79d2\u6216\u4ec5\u5269\u4e00\u4f4d\u7075\u9b42\u65f6\u6709\u8f85\u52a9\u63a8\u8fdb\u673a\u5236\\n  - \u5728\u4f20\u9001\u95e8\u672a\u5f00\u542f\u65f6\uff0c\u6c14\u606f\u63a2\u6d4b\u4f9d\u65e7\u751f\u6548\uff0c\u4ec5\u6709\u5b88\u536b\u8005\u57fa\u7840\u52a0\u901f\uff1b\u5f00\u542f\u540e\u4e0e\u539f\u673a\u5236\u76f8\u540c\\n- \u8c03\u6574\u5355\u5c40\u8868\u73b0\u5206\u8ba1\u7b97\u65b9\u5f0f\\n- \u8c03\u6574\u7b49\u7ea7\u8ba1\u7b97\u89c4\u5219\u4e0e\u7b49\u7ea7\u4e0a\u9650\\n- \u4f18\u5316\u5404\u5730\u56fe\u4e0e\u5404\u90e8\u5206\u97f3\u6548\\n- \u79fb\u9664\u521d\u59cb\u51b7\u5374\u65f6\u95f4\u4e3a 120% \u7684\u673a\u5236\\n- \u79fb\u9664\u9488\u950b\u5954\u9003\u6a21\u5f0f\u4e0b\u7684\u5404\u7c7b\u901f\u7387\u52a0\u500d\\n- \u4fee\u590d\u5730\u56fe\u5185\u90e8\u5206\u7269\u4ef6\u53ef\u5f02\u5e38\u4ea4\u4e92\u7684\u95ee\u9898\\n- \u4fee\u590d\u6781\u7aef\u60c5\u51b5\u4e0b\uff0c\u5b88\u536b\u8005\u51fb\u5012\u88ab\u91cd\u590d\u8ba1\u6570\u7684\u95ee\u9898\\n- \u4fee\u590d\u5782\u6b7b\u72b6\u6001\u7075\u9b42\u4f1a\u5728\u591a\u79cd\u60c5\u5883\u4e0b\u88ab\u9519\u8bef\u9009\u4e2d\u7684\u95ee\u9898\\n- \u4fee\u590d\u5404\u80fd\u529b\u5728\u5782\u6b7b\u6216\u64e6\u5200\u72b6\u6001\u4e0b\u4ecd\u7136\u53ef\u89e6\u53d1/\u751f\u6548/\u51b7\u5374\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u9b42\u6280\u80fd \u201c\u94e4\u800c\u8d70\u9669\u201d \u5728\u7279\u5b9a\u60c5\u51b5\u4e0b\u540c\u65f6\u89e6\u53d1\u591a\u4e2a\u6548\u679c\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u9b42\u5b88\u536b\u8005\u6280\u80fd \u201c\u5524\u7075\u7559\u8ff9\u201d \u52a0\u901f\u6548\u679c\u5e76\u672a\u751f\u6548\u53ca\u51b7\u5374/\u6301\u7eed\u65f6\u95f4\u6709\u8bef\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u9b42\u5b88\u536b\u8005\u5929\u8d4b \u201c\u9690\u4e8e\u8ff7\u96fe\u201d \u5b9e\u9645\u51b7\u5374\u91cd\u7f6e\u65f6\u673a\u4e0e\u63cf\u8ff0\u4e0d\u7b26\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u9b42\u5b88\u536b\u8005\u53ef\u4ee5\u53d7\u5230\u7206\u70b8\u4f24\u5bb3\u7684\u95ee\u9898\\n- \u4fee\u590d\u7075\u6c14\u6ee1\u6ea2\u65f6\u7075\u9b42\u5b88\u536b\u8005\u7ed3\u675f\u64e6\u5200\u65f6\u4e22\u5931\u5f3a\u5316\u6548\u679c\u7684\u95ee\u9898\\n- \u4fee\u590d\u7279\u5b9a\u60c5\u51b5\u4e0b\u8fdb\u5165\u7075\u6c14\u6ee1\u6ea2\u65f6\u5b88\u536b\u8005\u79fb\u901f\u9519\u8bef\u7684\u95ee\u9898\\n- \u4fee\u590d\u6548\u679c\u300c\u8bc5\u6012\u300d\u5728\u4ea4\u4e92\u5b8c\u6210\u540e\u4e0d\u751f\u6548\u7684\u95ee\u9898\\n- \u4fee\u590d\u751f\u6210\u65b0\u7075\u9b42\u5b9d\u7269\u76d2\u65f6\u53ef\u80fd\u4e0e\u5df2\u6709\u7075\u9b42\u5b9d\u7269\u76d2\u91cd\u53e0\u7684\u95ee\u9898\\n- \u4fee\u590d\u5728\u7279\u5b9a\u64cd\u4f5c\u4e0b\uff0c\u53ef\u4ee5\u5728\u5782\u6b7b/\u64e6\u5200\u72b6\u6001\u4e0b\u79fb\u52a8\u7684\u95ee\u9898\\n\\n## \u5e73\u8861\\n- \u65b0\u589e\u591a\u4eba\u6e38\u620f\u5e73\u8861\u6027\u8c03\u901f\u673a\u5236\\n- \u65b0\u589e\u591a\u5b88\u536b\u7279\u6b8a\u673a\u5236\uff0c\u4ee5\u5e73\u8861\u6e38\u620f\\n  - \u7075\u9b42\u53d7\u5230\u7684\u4f24\u5bb3 -20%\\n  - \u989d\u5916\u751f\u6210\u4e00\u4e2a\u9690\u85cf\u4f20\u9001\u95e8\uff0c\u4ec5\u5728\u7075\u9b42\u9760\u8fd1\u6216\u5269\u4f59\u65f6\u95f4\u4e0d\u8db3 42 \u79d2\u65f6\u516c\u5f00\\n- \u5bf9\u5927\u91cf\u80fd\u529b\u8fdb\u884c\u4e86\u91cd\u7f6e\uff0c\u5177\u4f53\u8be6\u89c1\u6e38\u620f\u5185\u4ecb\u7ecd\\n- \u5b88\u536b\u8005\u6b66\u5668\u4e0d\u518d\u80fd\u4ea7\u751f\u66b4\u51fb\uff0c\u4e0d\u518d\u80fd\u89e6\u53d1\u6a2a\u626b\u4e4b\u5203\\n- \u6253\u5f00\u7075\u9b42\u5b9d\u7269\u76d2\u65f6\u7684\u6548\u679c\u66f4\u6539\uff1a\\n  - \u53cc\u65b9\u7684\u53d1\u5149\u6548\u679c\u76ee\u6807\u9009\u62e9\uff1a\u6700\u8fdc\u654c\u65b9 \u2192 \u6700\u8fd1\u654c\u65b9\\n  - \u53cc\u65b9\u7684\u53d1\u5149\u6548\u679c\u65f6\u957f\u52a0\u957f\uff1a3s \u2192 7s\\n  - \u5b88\u536b\u8005\u65b9\u901f\u5ea6\u6548\u679c\u65f6\u957f\u52a0\u957f\uff1a7s \u2192 10s\\n- \u6548\u679c\u300c\u8bc5\u5492\u300d\u8c03\u6574\uff1a\\n  - \u73af\u5883\u6548\u679c\u89e6\u53d1\u8303\u56f4\u964d\u4f4e\uff1a3.5 \u2192 2.5\\n  - \u53d1\u5149\u6548\u679c\u65f6\u957f\u52a0\u957f\uff1a3s \u2192 7s\\n  - \u5b88\u536b\u8005\u65b9\u901f\u5ea6\u65f6\u957f\u52a0\u957f\uff1a7s \u2192 15s\\n- \u8303\u56f4\u6027\u7075\u6c14\u673a\u5236\u751f\u6548\u8303\u56f4\u7f29\u5c0f\uff1a16 \u2192 12\\n- \u7075\u6c14\u521d\u8d77\u7684\u788e\u7247\u53d1\u5149\u65f6\u95f4\u52a0\u957f\uff1a3s \u2192 5s\\n- \u8e72\u4e0b\u4ea4\u4e92\u751f\u6548\u8303\u56f4\u7f29\u5c0f\uff1a1 \u2192 0.7\\n- \u7075\u9b42\u788e\u7247\u6536\u96c6\u6240\u7528\u65f6\u95f4\u63d0\u5347\uff1a3s \u2192 3.5s\\n- \u7075\u9b42\u4e4b\u706f\u70b9\u4eae\u6240\u7528\u65f6\u95f4\u63d0\u5347\uff1a5s \u2192 7s\\n- \u7075\u9b42\u5b9d\u7269\u76d2\u6253\u5f00\u6240\u7528\u65f6\u95f4\u63d0\u5347\uff1a4s \u2192 5s\\n- \u8131\u79bb\u5782\u6b7b\u540e\u52a0\u901f\u65f6\u95f4\u964d\u4f4e\uff1a20s \u2192 7s\\n- \u8131\u79bb\u5782\u6b7b\u540e\u65e0\u654c\u65f6\u95f4\u964d\u4f4e\uff1a20s \u2192 15s\\n- \u591a\u6b21\u5782\u6b7b\u60e9\u7f5a\u7531 4 \u6b21\u964d\u4f4e\u81f3\u6700\u4f4e 15 \u79d2\u6539\u4e3a 3 \u6b21\u964d\u4f4e\u81f3\u6700\u4f4e 20 \u79d2\\n\\n## \u6742\u9879\\n- \u4f18\u5316\u6570\u636e\u5305\u67b6\u6784\\n- \u65b0\u589e README \u7684\u82f1\u6587\u7248\u652f\u6301\\n- \u65b0\u589e\u6e38\u620f\u4eba\u6570\u9650\u5236\u4e3a\u6700\u9ad8 10 \u4eba\uff08\u8d85\u8fc7 10 \u4eba\u65f6\uff0c\u81ea\u52a8\u968f\u673a 10 \u4f4d\u73a9\u5bb6\uff09\\n- \u4fee\u6b63\u6216\u4f18\u5316\u90e8\u5206\u5df2\u6709\u6587\u672c"},{"id":"/2026/03/05/v1-0-x","metadata":{"permalink":"/MidSoul-Wiki/blog/2026/03/05/v1-0-x","source":"@site/blog/2026-03-05-v1-0-x.md","title":"v1.0.x \u7075\u9b42\u4e0e\u5b88\u536b","description":"\u9996\u6b21\u53d1\u5e03","date":"2026-03-05T07:36:29.000Z","tags":[{"inline":false,"label":"\u65b0\u529f\u80fd","permalink":"/MidSoul-Wiki/blog/tags/feature","description":"\u65b0\u589e\u529f\u80fd\u6216\u73a9\u6cd5"}],"hasTruncateMarker":true,"authors":[{"name":"\u5fc3\u706b\u8ba1\u5212","title":"\u5236\u4f5c\u7ec4","url":"https://github.com/heart-fire-project","key":"hfp","page":null}],"frontMatter":{"title":"v1.0.x \u7075\u9b42\u4e0e\u5b88\u536b","date":"2026-03-05T07:36:29.000Z","authors":["hfp"],"tags":["feature"]},"unlisted":false,"prevItem":{"title":"v2.0.x \u56de\u54cd\u7eaa\u5143","permalink":"/MidSoul-Wiki/blog/2026/03/05/v2-0-x"}},"content":"## \u9996\u6b21\u53d1\u5e03\\n\\n\u300a\u5348\u591c\u7075\u9b42\u300b(MidSoul) \u9879\u76ee\u6b63\u5f0f\u53d1\u5e03 1.0 \u7248\u672c\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n- \u786e\u7acb\u4e86\u6838\u5fc3\u7684\u300c\u7075\u9b42 vs \u5b88\u536b\u300d\u6e38\u620f\u5bf9\u6297\u903b\u8f91\u3002\\n- \u5305\u542b\u4e86\u57fa\u7840\u7684\u5730\u56fe\u4ea4\u4e92\u3001\u6280\u80fd\u7cfb\u7edf\u4e0e\u7ed3\u7b97\u6d41\u7a0b\u3002"}]}}')}}]);